$p="C:\phwyverysad"; $u="https://github.com/LightnigFast/Project-Lightning/releases/download/v4.0.1.0/ProjectLightningInstaller.exe"; $f="$p\ProjectLightningInstaller.exe"; [Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $oldP=$ProgressPreference; $ProgressPreference='SilentlyContinue'; if(!(Test-Path $p)){New-Item -ItemType Directory -Path $p -Force | Out-Null}; try{Write-Host "Downloading..."; (New-Object System.Net.WebClient).DownloadFile($u,$f); if(Test-Path $f){Write-Host "Installing..."; Start-Process -FilePath $f -ArgumentList "/VERYSILENT /SUPPRESSMSGBOXES /NORESTART" -Wait}}catch{Write-Host "Error: $_"}finally{Write-Host "Cleaning up..."; Start-Sleep -Seconds 2; if(Test-Path $p){Remove-Item -Path $p -Recurse -Force -ErrorAction SilentlyContinue}; $ProgressPreference=$oldP; Write-Host "Done."}